using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer;

/// <summary>
/// MCP tools that wrap a weather REST API.
/// The SDK discovers methods marked with [McpServerTool] and uses
/// [Description] attributes to generate the tool schema for LLMs.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools
{
    private readonly HttpClient _http;

    // Constructor-injected HttpClient — resolved via DI (see Program.cs).
    public WeatherTools(HttpClient http)
    {
        _http = http;
    }

    [McpServerTool("get_current_weather")]
    [Description("Gets current weather for a city, including temperature and conditions.")]
    public async Task<string> GetCurrentWeather(
        [Description("City name, e.g. 'London' or 'New York'")] string city,
        [Description("Temperature unit: 'celsius' or 'fahrenheit' (default: celsius)")]
        string units = "celsius",
        CancellationToken cancellationToken = default)
    {
        var url = $"https://api.weatherapi.com/v1/current.json?key=DEMO_KEY&q={Uri.EscapeDataString(city)}";
        var response = await _http.GetAsync(url, cancellationToken);

        if (!response.IsSuccessStatusCode)
        {
            return $"Error: could not fetch weather for '{city}' (HTTP {(int)response.StatusCode}).";
        }

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        using var doc = JsonDocument.Parse(json);
        var current = doc.RootElement.GetProperty("current");

        var tempC = current.GetProperty("temp_c").GetDouble();
        var condition = current.GetProperty("condition").GetProperty("text").GetString();
        var humidity = current.GetProperty("humidity").GetInt32();

        var temp = units == "fahrenheit"
            ? $"{current.GetProperty("temp_f").GetDouble()} °F"
            : $"{tempC} °C";

        return $"Weather in {city}: {condition}, {temp}, humidity {humidity}%";
    }

    [McpServerTool("get_forecast")]
    [Description("Gets a multi-day weather forecast for a city.")]
    public async Task<string> GetForecast(
        [Description("City name")] string city,
        [Description("Number of forecast days (1-3, default: 3)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        days = Math.Clamp(days, 1, 3);
        var url = $"https://api.weatherapi.com/v1/forecast.json?key=DEMO_KEY&q={Uri.EscapeDataString(city)}&days={days}";
        var response = await _http.GetAsync(url, cancellationToken);

        if (!response.IsSuccessStatusCode)
        {
            return $"Error: could not fetch forecast for '{city}' (HTTP {(int)response.StatusCode}).";
        }

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        using var doc = JsonDocument.Parse(json);
        var forecastDays = doc.RootElement
            .GetProperty("forecast")
            .GetProperty("forecastday");

        var lines = new List<string> { $"Forecast for {city}:" };

        foreach (var day in forecastDays.EnumerateArray())
        {
            var date = day.GetProperty("date").GetString();
            var dayData = day.GetProperty("day");
            var maxC = dayData.GetProperty("maxtemp_c").GetDouble();
            var minC = dayData.GetProperty("mintemp_c").GetDouble();
            var cond = dayData.GetProperty("condition").GetProperty("text").GetString();
            lines.Add($"  {date}: {cond}, {minC}-{maxC} °C");
        }

        return string.Join('\n', lines);
    }
}

